  "handoff_brief": {
    "recipient": "Shaq",
    "task_context": "Implement an Order State Management feature within the Order Fulfillment bounded context. The system must enforce strict state transition rules on orders and gate refund issuance on order state. Bird defined two domain invariants (no backward state transitions from SHIPPED to PENDING; refunds only on DELIVERED orders). MJ designed a PATCH endpoint for state changes, an OrderStateMachine for transition validation, and a separate RefundService that verifies order state before issuing refunds.",
    "domain_rules": [
      {
        "rule": "An order cannot transition from SHIPPED to PENDING",
        "testable_assertion": "Calling PATCH /orders/{id}/state with target state PENDING on an order currently in SHIPPED state returns 422 with error code ORDER_STATE_INVALID"
      },
      {
        "rule": "A refund can only be issued on a DELIVERED order",
        "testable_assertion": "RefundService.Issue(orderId) throws or returns an error when the order's current state is anything other than DELIVERED"
      }
    ],
    "architecture_guidance": [
      {
        "decision": "State transitions are exposed via PATCH /orders/{id}/state",
        "implementation_note": "The endpoint receives the desired target state in the request body. Validation is delegated to OrderStateMachine before any persistence occurs. Return 422 with error code ORDER_STATE_INVALID for illegal transitions."
      },
      {
        "decision": "Transition validation lives in an OrderStateMachine class",
        "implementation_note": "OrderStateMachine owns the full map of allowed transitions. It should be a pure domain object with no infrastructure dependencies so it is easy to unit test. All state change requests — from the API and from internal services — must pass through this class."
      },
      {
        "decision": "Refund logic is separated into a RefundService",
        "implementation_note": "RefundService calls the order service (or queries order state directly) to verify the order is in DELIVERED state before issuing a refund. This keeps refund concerns decoupled from order state management while still enforcing the domain invariant."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "Reject illegal backward state transition",
        "given": "An order in SHIPPED state",
        "when": "A revert-to-pending is attempted via PATCH /orders/{id}/state with target state PENDING",
        "then": "The request is rejected with HTTP 422 and error code ORDER_STATE_INVALID; the order remains in SHIPPED state"
      },
      {
        "criterion": "Allow refund only on delivered orders",
        "given": "An order in DELIVERED state",
        "when": "A refund is requested through RefundService",
        "then": "The refund is issued successfully"
      },
      {
        "criterion": "Reject refund on non-delivered orders",
        "given": "An order in any state other than DELIVERED (e.g., SHIPPED, PENDING, CANCELLED)",
        "when": "A refund is requested through RefundService",
        "then": "The refund is rejected with an appropriate error indicating the order is not in a refundable state"
      }
    ],
    "terminology_alignment": [
      {
        "domain_term": "Order state invariant",
        "technical_term": "OrderStateMachine transition guard",
        "definition": "A business rule that forbids certain state transitions. Implemented as guard clauses in OrderStateMachine that reject invalid target states."
      },
      {
        "domain_term": "Revert-to-pending",
        "technical_term": "PATCH /orders/{id}/state with body {state: PENDING}",
        "definition": "An attempt to move an order backward to PENDING. This is the specific illegal transition Bird identified."
      }
    ],
    "contradictions_resolved": [],
    "open_questions": []
  },
  "escalations": [],
  "confidence": {
    "level": 92,
    "high_confidence_areas": [
      "Domain invariants are clearly defined and directly map to testable assertions",
      "Architecture decisions are consistent with domain rules — no conflicts between Bird and MJ",
      "Acceptance criteria cover both the happy path and rejection path for refunds"
    ],
    "low_confidence_areas": [
      "Full set of valid order states and transitions not specified — only PENDING, SHIPPED, and DELIVERED mentioned explicitly; Shaq may need to clarify the complete state graph",
      "Error handling contract for RefundService (HTTP status code, error code) not explicitly defined by Bird or MJ"
    ],
    "assumptions": [
      "ORDER_STATE_INVALID is the shared error code for all illegal state transitions, not just the SHIPPED-to-PENDING case",
      "RefundService communicates with the order service via an internal call rather than through the public PATCH endpoint"
    ]
  }
}

